CREATE TABLE IF NOT EXISTS location_hours (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), location_id UUID REFERENCES locations(id) ON DELETE CASCADE, day_of_week INTEGER NOT NULL, slot_number INTEGER NOT NULL, start_time TIME WITHOUT TIME ZONE NOT NULL, end_time TIME WITHOUT TIME ZONE NOT NULL, created_at TIMESTAMPTZ DEFAULT NOW(), UNIQUE(location_id, day_of_week, slot_number));
